base_css:
body {
      margin: 0;
      font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      background-color: var(--bg-body);
      color: var(--text);
      overflow-x: hidden;
      padding-top: var(--header-h);
    }
    @media (max-width: 991px) { body { padding-top: 64px; } }

    a { text-decoration: none; color: var(--primary); transition: color var(--t); }
    a:hover { color: var(--primary-2); }
    p { line-height: 1.7; color: var(--text-s); font-size: 0.95rem; }
    .font-syne { font-family: 'Syne', sans-serif; }

    /* ══════════════════════════════════════════════════════
       HERO
    ══════════════════════════════════════════════════════ */
    .hero-banner {
      position: relative; overflow: hidden;
      background: linear-gradient(135deg, var(--digital-blue-950) 0%, var(--digital-blue-900) 50%, var(--digital-blue-800) 100%);
      padding: 80px 0 110px; text-align: center;
    }
    .hero-banner::before {
      content: ''; position: absolute; inset: 0;
      background-image:
        radial-gradient(circle at 15% 50%, rgba(51,133,255,0.2), transparent 30%),
        radial-gradient(circle at 85% 30%, rgba(51,133,255,0.2), transparent 30%);
      z-index: 1; pointer-events: none;
    }
    .hero-ring { position: absolute; border-radius: 50%; pointer-events: none; z-index: 1; }
    .hero-ring-1 { width: 600px; height: 600px; top: -200px; left: -150px; border: 1px solid rgba(51,133,255,0.15); }
    .hero-ring-2 { width: 400px; height: 400px; bottom: -100px; right: -50px; border: 1px solid rgba(255,255,255,.05); }
    .hero-content { position: relative; z-index: 3; max-width: 800px; margin: 0 auto; }

    .hero-breadcrumb {
      display: inline-flex; align-items: center; gap: 8px;
      color: var(--gold); font-size: .75rem; font-weight: 800;
      text-transform: uppercase; letter-spacing: 0.08em;
      background: rgba(51,133,255,0.15); border: 1px solid rgba(51,133,255,0.3);
      border-radius: 50px; padding: 6px 16px; margin-bottom: 24px; transition: all var(--t);
    }
    .hero-breadcrumb:hover { background: rgba(51,133,255,0.25); color: #fff; transform: translateY(-2px); }

    .hero-banner h1 {
      font-size: clamp(2.5rem, 5vw, 3.8rem); font-weight: 800; color: #fff;
      letter-spacing: -.02em; margin-bottom: 16px; text-shadow: 0 4px 20px rgba(0,0,0,0.3);
    }
    .hero-banner p { font-size: 1.15rem; color: rgba(255,255,255,.75); line-height: 1.7; margin-bottom: 0; }

    /* Stats in hero */
    .hero-stats {
      display: flex; justify-content: center; gap: 32px; margin-top: 36px; flex-wrap: wrap;
    }
    .hero-stat {
      background: rgba(255,255,255,0.08); border: 1px solid rgba(255,255,255,0.12);
      border-radius: 16px; padding: 16px 28px; text-align: center; min-width: 100px;
    }
    .hero-stat-num { font-size: 1.8rem; font-weight: 800; color: #fff; line-height: 1; }
    .hero-stat-lbl { font-size: .72rem; font-weight: 700; color: rgba(255,255,255,.6); text-transform: uppercase; letter-spacing: .06em; margin-top: 4px; }

    /* ══════════════════════════════════════════════════════
       CONTROLS
    ══════════════════════════════════════════════════════ */
    .controls-wrap {
      margin-top: -38px; position: relative; z-index: 10; margin-bottom: 40px;
      display: flex; flex-direction: column; align-items: center; gap: 18px;
    }
    .search-box { width: 100%; max-width: 520px; position: relative; }
    .search-box input {
      width: 100%; padding: 15px 24px 15px 50px; border-radius: 50px;
      border: 1px solid var(--bdr); background: #fff; box-shadow: var(--sh-md);
      font-family: inherit; font-size: .95rem; transition: all var(--t); outline: none;
    }
    .search-box input:focus { border-color: var(--primary); box-shadow: 0 8px 30px rgba(0,102,255,0.12); }
    .search-box i { position: absolute; left: 20px; top: 50%; transform: translateY(-50%); color: var(--text-m); font-size: 1.15rem; }

    .filter-tabs { display: flex; flex-wrap: wrap; gap: 10px; justify-content: center; }
    .filter-tab {
      padding: 10px 22px; border-radius: 50px; background: #fff;
      border: 1px solid var(--bdr); font-weight: 700; font-size: .85rem;
      color: var(--text-m); cursor: pointer; transition: all var(--t); box-shadow: var(--sh-xs);
    }
    .filter-tab:hover { border-color: var(--primary-l); color: var(--primary); transform: translateY(-2px); box-shadow: var(--sh-sm); }
    .filter-tab.active {
      background: var(--primary); color: #fff; border-color: var(--primary);
      box-shadow: 0 6px 16px rgba(0,102,255,0.25); transform: translateY(-2px);
    }

    /* ══════════════════════════════════════════════════════
       DOWNLOADS LIST
    ══════════════════════════════════════════════════════ */
    .dl-section { margin-bottom: 48px; }
    .dl-section-header {
      display: flex; align-items: center; gap: 14px;
      margin-bottom: 20px; padding-bottom: 14px;
      border-bottom: 2px solid var(--bdr);
    }
    .dl-section-icon {
      width: 44px; height: 44px; border-radius: 12px;
      background: var(--primary-xl); color: var(--primary);
      display: flex; align-items: center; justify-content: center;
      font-size: 1.3rem; flex-shrink: 0; border: 1px solid var(--primary-l);
    }
    .dl-section-title { font-family: 'Syne', sans-serif; font-size: 1.25rem; font-weight: 800; color: var(--primary-d); margin: 0; }
    .dl-section-count {
      margin-left: auto; background: var(--primary-xl); color: var(--primary);
      font-size: .75rem; font-weight: 800; padding: 4px 12px; border-radius: 50px;
      border: 1px solid var(--primary-l);
    }

    /* Individual download row */
    .dl-item {
      display: flex; align-items: center; gap: 16px;
      background: #fff; border-radius: 14px; padding: 18px 20px;
      border: 1px solid var(--bdr); box-shadow: var(--sh-xs);
      transition: all var(--t); margin-bottom: 10px;
      animation: fadeInSlideUp 0.35s ease-out forwards; opacity: 0;
    }
    .dl-item:hover { transform: translateY(-3px); box-shadow: var(--sh-sm); border-color: var(--primary-l); }

    @keyframes fadeInSlideUp {
      from { opacity: 0; transform: translateY(16px); }
      to   { opacity: 1; transform: translateY(0); }
    }

    .dl-file-icon {
      width: 48px; height: 48px; border-radius: 12px; flex-shrink: 0;
      display: flex; align-items: center; justify-content: center;
      font-size: 1.4rem; font-weight: 900;
    }
    .dl-file-icon.pdf  { background: #fff1f0; color: #e53935; border: 1px solid rgba(229,57,53,0.15); }
    .dl-file-icon.doc  { background: #e8f0fe; color: #1a73e8; border: 1px solid rgba(26,115,232,0.15); }
    .dl-file-icon.xls  { background: #e6f4ea; color: #1e8e3e; border: 1px solid rgba(30,142,62,0.15); }
    .dl-file-icon.img  { background: #fce8ff; color: #9c27b0; border: 1px solid rgba(156,39,176,0.15); }
    .dl-file-icon.zip  { background: #fff8e1; color: #f9a825; border: 1px solid rgba(249,168,37,0.15); }
    .dl-file-icon.file { background: var(--primary-xl); color: var(--primary); border: 1px solid var(--primary-l); }

    .dl-info { flex: 1; min-width: 0; }
    .dl-title {
      font-size: 1rem; font-weight: 700; color: var(--primary-d);
      margin: 0 0 4px 0; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
    }
    .dl-meta { display: flex; align-items: center; gap: 14px; flex-wrap: wrap; }
    .dl-meta span {
      font-size: .78rem; font-weight: 600; color: var(--text-m);
      display: inline-flex; align-items: center; gap: 5px;
    }
    .dl-meta .badge-cat {
      background: var(--primary-xl); color: var(--primary);
      padding: 2px 10px; border-radius: 50px; font-size: .72rem; font-weight: 800;
      border: 1px solid var(--primary-l);
    }

    .dl-btn {
      flex-shrink: 0; display: inline-flex; align-items: center; gap: 8px;
      background: var(--primary); color: #fff; font-weight: 700; font-size: .85rem;
      padding: 10px 20px; border-radius: 50px; border: none; cursor: pointer;
      transition: all var(--t); box-shadow: 0 4px 12px rgba(0,102,255,0.25); white-space: nowrap;
    }
    .dl-btn:hover { background: var(--primary-2); transform: translateY(-2px); box-shadow: 0 6px 18px rgba(0,102,255,0.35); color: #fff; }
    .dl-btn:active { transform: translateY(0); }

    @media (max-width: 600px) {
      .dl-item { flex-wrap: wrap; }
      .dl-btn  { width: 100%; justify-content: center; }
      .dl-title { white-space: normal; }
    }

    /* ══════════════════════════════════════════════════════
       LOADING / ERROR / EMPTY
    ══════════════════════════════════════════════════════ */
    .dl-loader {
      display: flex; flex-direction: column;
      align-items: center; justify-content: center;
      padding: 80px 20px; gap: 20px;
    }
    .dl-loader-spinner {
      width: 52px; height: 52px; border-radius: 50%;
      border: 4px solid var(--primary-l); border-top-color: var(--primary);
      animation: spin 0.8s linear infinite;
    }
    @keyframes spin { to { transform: rotate(360deg); } }
    .dl-loader p { margin: 0; color: var(--text-m); font-weight: 600; font-size: 1rem; }

    .dl-state {
      text-align: center; padding: 60px 20px;
      background: #fff; border-radius: 16px; margin-bottom: 20px;
    }
    .dl-state.error { border: 1px solid rgba(239,68,68,0.2); }
    .dl-state.empty { border: 1px dashed var(--bdr); }
    .dl-state i { font-size: 2.5rem; display: block; margin-bottom: 12px; }
    .dl-state.error i { color: var(--error); }
    .dl-state.empty i { color: var(--text-m); }
    .dl-state h4 { color: var(--primary-d); font-weight: 800; margin-bottom: 8px; }
    .dl-state p  { color: var(--text-m); margin: 0; }

    /* ══════════════════════════════════════════════════════
       SCROLL REVEAL
    ══════════════════════════════════════════════════════ */
    .fade-up { opacity: 0; transform: translateY(28px); transition: opacity .6s var(--ease), transform .6s var(--ease); }
    .fade-up.visible { opacity: 1; transform: translateY(0); }
    .fade-in { opacity: 0; transition: opacity .6s var(--ease); }
    .fade-in.visible { opacity: 1; }
    .delay-1 { transition-delay: .05s; }
    .delay-2 { transition-delay: .1s; }

